-- Seed data for public.research_papers
begin;
delete from public.research_papers;

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-mental', '活力・メンタル', 1, 1, '健常者のメンタルヘルスへの影響', '主な機関：日本国内大学', 'ムクナ豆のお茶を飲むと、朝の目覚めがスッキリし、日中の「なんだか疲れた」が軽くなって、毎日を前向きに過ごせるようになります。', 'https://center6.umin.ac.jp/cgi-open-bin/ctr/ctr_view.cgi?recptno=R000068082', '1. 研究の目的', '健常な成人男女を対象に、ムクナ豆茶の継続摂取が日常的なストレス、疲労感、睡眠の質、および心理的な「幸福感」にどのような影響を与えるかを科学的に検証する。', '2. 研究内容', '焙煎ムクナ豆茶摂取群とプラセボ群に分けた二重盲検比較試験を実施。心理尺度評価や睡眠計を用いた客観的データ解析を行い、精神的健康状態の変化を多角的に測定した。', '3. 研究成果', '起床時の眠気改善や日中の疲労感軽減が有意に示された。ドーパミン代謝のサポートを通じて「幸福感」スコアが向上し、レジリエンス向上に寄与する可能性が示唆された。', '4. 重要なポイント', 'ムクナ豆が病者だけでなく、健常者の「心の健康」や「睡眠の質」を底上げする機能性食品として有効である可能性。', true);

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-mental', '活力・メンタル', 1, 2, 'パーキンソン病患者の「ON時間」延長とQOL', '主な機関：順天堂大学', 'お薬の効き目が切れて動けなくなる時間を減らし、副作用のガタガタした動きを抑えて、元気に動ける時間を長くしてくれる心強い味方です。', 'https://pmc.ncbi.nlm.nih.gov/articles/PMC11557210/', '1. 研究の目的', 'L-ドパ製剤を服用中の患者において、日本産ムクナ豆の併用が「OFF時間」を短縮し、副作用を抑えつつ「ON時間（動ける時間）」を延長できるかを調査する。', '2. 研究内容', '臨床現場にて患者に日本産ムクナ豆粉末を投与し、血中L-ドパ濃度の推移と運動症状を観察。標準製剤単独投与時と比較して、改善持続時間や不随意運動の発現頻度を分析した。', '3. 研究成果', '標準薬に比べ血中濃度の上昇が速やかで、効果の持続が長い「ON時間の延長」を確認。不随意運動を悪化させずに運動機能を維持でき、天然成分特有の利点が証明された。', '4. 重要なポイント', '標準薬の課題である「効果の減衰」を、天然ムクナ豆の多成分シナジーが補完し、生活の質を劇的に改善する。', true);

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-mental', '活力・メンタル', 1, 3, '糖尿病モデルにおける性行動・リビドー改善', '主な機関：CiNii Research', '生活習慣病による体の衰えや、夫婦の夜の悩み、活力の低下を、天然の成分が内側から若々しくサポートしてくれます。', 'https://cir.nii.ac.jp/crid/1361137045495310208', '1. 研究の目的', '高血糖（糖尿病）が原因で生じる性機能障害や性欲減退に対し、ムクナ豆抽出物がホルモンバランスを整え、生殖機能および性行動を回復させる効果があるかを検証する。', '2. 研究内容', '糖尿病ラットにムクナ豆抽出物を投与。交尾行動の頻度を観察するとともに、血清中のテストステロン値、精子の質、酸化ストレス指標を測定し、プラセボ群と比較した。', '3. 研究成果', '投与群では低下していたテストステロン値が有意に上昇し、性行動の回数と意欲が回復した。また、精巣細胞の酸化ストレスが軽減されており、生殖システムへの防御機能が確認された。', '4. 重要なポイント', 'L-ドパによる脳内報酬系の活性化と、抗酸化作用の両面から「性欲」と「生殖機能」の両方を改善・保護する。', true);

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-mental', '活力・メンタル', 1, 4, '臨床的可能性についての総合討論', '主な機関：予防鍼灸研究会', '昔から「元気の源」とされてきた秘密を探り、心の落ち込みや不妊、免疫アップなど、現代人のあらゆる悩みに効く可能性を専門家たちが太鼓判。', 'https://www.sgpam-japan.jp/wp-content/uploads/2024/06/j-pam_v2n1-03-2.pdf', '1. 研究の目的', 'アーユルヴェーダ等で古くから利用されてきたムクナ豆を現代医学の視点で見直し、免疫調整、抗腫瘍、神経保護など、多岐にわたる臨床応用の可能性を統合的に議論する。', '2. 研究内容', '医師、研究者が集まり、ムクナ豆に含まれるL-ドパや5,000種以上の微量成分の相互作用を検討。臨床例に基づき、鬱、不妊、免疫疾患等への適応症の展望を考察した。', '3. 研究成果', 'ムクナ豆は「アダプトゲン（ストレスへの適応力を高める物質）」として機能すると定義。癌化学療法の副作用軽減や、精神疾患におけるレジリエンス強化への応用が期待される。', '4. 重要なポイント', '単一成分の薬とは異なり、体全体のバランスを整える「ホリスティックな治療補助剤」としての価値を再評価。', true);

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-mental', '活力・メンタル', 1, 5, 'ショウジョウバエモデルでの寿命延長と活力', '主な機関：パウリスタ大学', '細胞レベルから老化を防いで、いつまでもハツラツと元気に動き回れる「健康長寿」の秘訣が、この豆には詰まっています。', 'https://journals.plos.org/plosone/article?id=10.1371/journal.pone.0110802', '1. 研究の目的', '遺伝的な神経変性モデルを用いて、ムクナ豆が細胞内のエネルギー工場であるミトコンドリアの機能を守り、生存率や運動能力を維持できるかをミクロの視点から解析する。', '2. 研究内容', 'パーキンソン病に似た症状を持つハエに対し、ムクナ豆抽出物を投与。寿命の推移を記録するとともに、飛行・歩行能力テストを実施し、脳組織の神経細胞脱落状況を観察した。', '3. 研究成果', 'ムクナ豆はミトコンドリアの酸化的損傷を抑制し、神経細胞死を有意に防御した。その結果、寿命が大幅に延び、加齢に伴う運動能力の低下も抑制されることが実証された。', '4. 重要なポイント', '神経変性を「予防」し、細胞レベルから寿命と活力を引き出す神経保護効果が客観的に実証された。', true);

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-body', '身体ケア・生活', 2, 1, '最適な浸漬・加熱条件（軟化プロセス）', '主な機関：お茶の水女子大学', 'カチカチに硬いムクナ豆を、お家でふっくら美味しく料理するための「魔法の温度と待ち時間」を科学的に見つけ出しました。', 'https://www.jstage.jst.go.jp/article/cookeryscience/42/2/42_93/_article/-char/ja/', '1. 研究の目的', 'ムクナ豆の硬い種皮が吸水を阻害する問題を解決するため、調理時間を短縮し、かつ食感を損なわないための最適な予備処理条件（温度・時間）を明らかにすることを目的とする。', '2. 研究内容', '異なる水温における吸水速度を計測。また、加熱後の豆の硬さを測定し、組織の軟化プロセスを顕微鏡観察。デンプンの糊化状態と細胞壁の崩壊度を時間軸に沿って分析した。', '3. 研究成果', '90℃の熱湯に浸漬した場合、わずか4時間で完全に吸水し、その後の加熱による軟化が劇的にスムーズになることが判明。従来1日以上かかっていた調理が数時間に短縮可能となった。', '4. 重要なポイント', '「90℃・4時間浸漬」という具体的な指標を確立し、家庭や食品加工現場での実用性を飛躍的に高めた。', true);

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-body', '身体ケア・生活', 2, 2, 'ムクナ豆味噌の調製と抗酸化能', '主な機関：東洋大学', 'ムクナ豆をお味噌にすると、栄養成分がさらにパワーアップ！普通のお味噌より数倍も「体をサビさせない力」が強い、最強の健康調味料になります。', 'https://www.jstage.jst.go.jp/article/cookeryscience/50/5/50_174/_article/-char/ja/', '1. 研究の目的', 'ムクナ豆を日本の伝統的な発酵食品である味噌に加工することで、成分がどのように変化するかを調査し、高機能かつ安全な新しい発酵食品としての可能性を評価する。', '2. 研究内容', '蒸したムクナ豆に米麹と塩を加え発酵・熟成させた。製造工程におけるL-ドパ残存量、アミノ酸組成、抗酸化活性の変化を測定。通常の大豆味噌と比較して、成分特性を評価した。', '3. 研究成果', '発酵の過程でL-ドパはほぼ完全に消失し、代わりに強力な抗酸化物質が生成された。抗酸化能は大豆味噌の数倍に達し、L-ドパを避けたい層でも安心して食べられることが示された。', '4. 重要なポイント', '発酵というプロセスにより、特定の成分（L-ドパ）を無害化しつつ、抗酸化力を極大化できることを証明。', true);

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-body', '身体ケア・生活', 2, 3, '重曹添加によるL-ドパ含有量の制御', '主な機関：東洋大学', '料理に「重曹」を少し加えるだけで、成分の強さを自分好みに調整できる、安心・安全なキッチン裏ワザを確立しました。', 'https://www.jstage.jst.go.jp/article/jhej/71/6/71_392/_article/-char/ja/', '1. 研究の目的', '調理過程において、アルカリ性下でL-ドパが分解されやすい性質を利用し、食品中のL-ドパ含量を意図的にコントロールする調理手法を確立することを目的とする。', '2. 研究内容', '加熱調理時に重曹を添加し、その濃度や加熱時間がL-ドパ残存量に与える影響を定量分析。また、重曹処理による豆の軟化促進効果や、風味・色調の変化についても検証した。', '3. 研究成果', '重曹の添加によりL-ドパの分解が加速し、短時間の加熱で含有量を大幅に減らすことが可能となった。これにより、特定の層向けの「安全な調理マニュアル」の構築が可能となった。', '4. 重要なポイント', '化学的なアプローチ（重曹）により、ムクナ豆の機能性を「抜く」自由度を調理者に与えた研究。', true);

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-body', '身体ケア・生活', 2, 4, '焙煎と発酵処理による成分変化の比較', '主な機関：東洋大学', '「香ばしく焼く」か「発酵させる」か。なりたい自分に合わせて、ムクナ豆のパワーを上手に引き出す使い分けのコツを教えます。', 'https://pub.confit.atlas.jp/ja/event/jshe77/presentation/3K1268-89-09', '1. 研究の目的', '「加熱（焙煎）」と「発酵」という異なる加工法が、ムクナ豆の有効成分や抗酸化能に与える影響を比較し、目的別の最適な加工フローを提示することを目的とする。', '2. 研究内容', '焙煎処理と発酵処理を並行して実施。それぞれの過程でのL-ドパの熱安定性、メラノイジン（抗酸化成分）の生成、およびタンパク質分解率を詳細にデータ化して比較分析した。', '3. 研究成果', 'L-ドパを最大限保持するには短時間の低温焙煎が適しており、逆に抗酸化力を高めつつ安全性を確保するには発酵が適していることが明らかになり、科学的根拠を提示した。', '4. 重要なポイント', '食べ方の目的（ドーパミン補給か、抗酸化ケアか）に応じた明確な「加工の分岐点」を示した。', true);

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-body', '身体ケア・生活', 2, 5, '有効利用に関する調理科学的研究', '主な機関：東洋大学', 'お料理の隠し味や、甘酒・ドリンクなど、毎日の食卓にパッと取り入れられる「ムクナ豆の美味しい活用アイデア」が満載です。', 'https://toyo.repo.nii.ac.jp/record/14388/files/kogyogijutsu45_066-069.pdf', '1. 研究の目的', 'ムクナ豆を現代の多様な食生活に適合させるため、ペースト、粉末、甘酒などの新しい形態への加工適性を研究し、未利用資源の産業的活用法を構築することを目的とする。', '2. 研究内容', '豆の脱皮、粉砕、酵素分解の各プロセスが食感や風味に与える影響を調査。特に甘酒などの飲料へ加工した際の栄養価維持率や、乳化剤としての加工特性を実験を通じて検証した。', '3. 研究成果', 'ムクナ豆ペーストは高い栄養価を維持したまま多様な料理に混ぜやすく、特に高齢者向けの嚥下食や機能性飲料としての適性が高いことが判明。食品素材としての再定義を行った。', '4. 重要なポイント', '豆のままでなく「素材（ペースト・粉末）」として活用することで、摂取の継続性と産業的価値を最大化した。', true);

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-prevention', '予防・保護', 3, 1, 'アルツハイマー病への予防効果', '主な機関：東京農業大学', '脳の中に溜まっていく「物忘れの原因」をお掃除して、大切な思い出や冴えた頭をいつまでも守ってくれる、脳のガードマンのような存在です。', 'https://www.nature.com/articles/s41598-022-04777-z', '1. 研究の目的', '認知症の大部分を占めるアルツハイマー病に対し、ムクナ豆が脳内の病因物質（アミロイドβ）の蓄積を抑え、記憶・学習能力を維持・改善できるかを検証することを目的とする。', '2. 研究内容', 'ADモデルマウスを用い、ムクナ豆粉末を配合した飼料を長期間摂取させた。迷路試験等で空間記憶能力を評価するとともに、脳内のプラーク蓄積面積を画像解析で定量化した。', '3. 研究成果', 'ムクナ豆摂取群は、対照群に比べて記憶力の低下が顕著に抑制された。脳内解析ではアミロイドβ沈着が有意に減少しており、脳内の「掃除」を促進している可能性が示唆された。', '4. 重要なポイント', 'ドーパミン補給にとどまらず、脳内の病理学的変化を直接「予防・抑制」する可能性を提示。', true);

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-prevention', '予防・保護', 3, 2, '生体内抗酸化機能と全身の健康維持', '主な機関：日本学術振興会', '全身の細胞が「錆びる」のを防いで、お肌や血管の若々しさをキープ。内側から美しく、年齢を感じさせない体づくりを助けます。', 'https://kaken.nii.ac.jp/file/KAKENHI-PROJECT-23500992/23500992seika.pdf', '1. 研究の目的', 'ムクナ豆が細胞内の酸化ストレスから体を守る仕組みを解明し、単なる栄養源ではない「生体調節機能食品」としての科学的根拠を遺伝子レベルから調査することを目的とする。', '2. 研究内容', '細胞および小動物を用い、ムクナ豆抽出物が抗酸化酵素の発現に与える影響を解析。酸化剤による細胞死に対する防御能を、ミトコンドリアの電位維持等を指標として測定した。', '3. 研究成果', 'ムクナ豆特有の多成分系が、細胞内の抗酸化ネットワークを強力に活性化することが判明。特に血管内皮細胞や神経細胞の保護効果が高く、全身の組織劣化抑制に寄与すると示された。', '4. 重要なポイント', '細胞を「錆び」から守り、神経や血管の健康を根本から維持する「防御的食品」としての機能を立証。', true);

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-prevention', '予防・保護', 3, 3, '肝細胞がんに対する抗遺伝子毒性', '主な機関：東京農工大学', '体の中の悪い物質やウイルスから細胞をガード。将来の大きな病気を防ぎ、ダメージを受けた細胞を優しくケアしてくれます。', 'https://pubmed.ncbi.nlm.nih.gov/34136158/', '1. 研究の目的', 'ムクナ豆に含まれる特定のペプチド成分が、発がん性物質やウイルスによる細胞ダメージをどの程度軽減し、がん細胞の増殖を抑えることができるかを解析することを目的とする。', '2. 研究内容', '抽出した特定タンパク質加水分解物（ペプチド）を、肝がん細胞株やC型肝炎ウイルス複製システムに添加。細胞の生存率、DNA損傷程度、ウイルスの増殖抑制効果をモニタリングした。', '3. 研究成果', '特定のムクナペプチドが肝がん細胞の増殖を抑制し、正常細胞のDNA損傷を保護する働きを示した。またウイルスの複製を阻害する活性も確認され、肝疾患予防への応用が期待される。', '4. 重要なポイント', '「L-ドパ以外」の成分（ペプチド）にも、がん予防やウイルス抑制などの高度な生体防御能があることを発見。', true);

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-prevention', '予防・保護', 3, 4, 'ロテノン誘導モデルへの神経炎症軽減効果', '主な機関：マヒドン大学', '脳の炎症という「ボヤ」を素早く消し止めて、パーキンソン病の始まりと言われる「においの鈍さ」などのトラブルを早めに食い止めます。', 'https://www.mdpi.com/1467-3045/46/8/545', '1. 研究の目的', '毒物（ロテノン）による神経ダメージがパーキンソン病を引き起こす点に着目し、ムクナ豆が脳内の炎症を鎮め、神経回路の損傷をどの程度防げるかを検証することを目的とする。', '2. 研究内容', 'ロテノン投与マウスにムクナ豆抽出物を投与。脳内の炎症に関わる細胞の活性化状態を観察し、ドーパミン神経の生存率や、嗅覚などの感覚機能の回復度合いを評価した。', '3. 研究成果', 'ムクナ豆は脳内の神経炎症を有意に抑制し、神経細胞の生存をサポートした。特に初期症状とされる「嗅覚低下」の改善が確認され、早期の神経保護における優位性が実証された。', '4. 重要なポイント', '炎症という「火事」を鎮めることで、神経が壊れる連鎖を食い止める「神経保護剤」としての実力を証明。', true);

insert into public.research_papers (category_id, category_name, category_sort, paper_sort, title, organization, summary, url, section1_heading, section1_body, section2_heading, section2_body, section3_heading, section3_body, section4_heading, section4_body, published)
values ('cat-prevention', '予防・保護', 3, 5, '標準薬と同等の有効性と安全性', '主な機関：ローマ・大学', '病院で出されるお薬と同じくらいしっかりと体に効きながら、天然成分だからこその「優しさ」で、体への負担を少なく元気を支えます。', 'https://academia.carenet.com/share/news/c24d796e-2d76-4f8f-8c86-0f60e265e823', '1. 研究の目的', '医療用レボドパ製剤の使用が困難な環境や初期患者において、天然のムクナ豆粉末がどの程度「医薬品の代わり」として通用するかを厳格な臨床基準で検証することを目的とする。', '2. 研究内容', '未治療の患者を対象に、標準的なレボドパ製剤投与群とムクナ豆投与群に分け、運動スコアの改善度、血中濃度の持続性、および副作用の発生率を比較した。', '3. 研究成果', 'ムクナ豆粉末は標準製剤と同等の運動機能改善効果を示した。さらに、副作用（ジスキネジア等）が少なく、天然成分としての安全性と有効性のバランスが極めて高いことが確定した。', '4. 重要なポイント', '「薬と同等」の結果が、現代医学の厳格な臨床試験（RCT）で認められた、ムクナ豆の信頼性の柱となる研究。', true);

